export interface ApiBlogPostBlogPost extends Schema.CollectionType {
  collectionName: 'blog_posts';
  info: {
    description: 'Blog posts with editorial workflow';
    displayName: 'Blog Post';
    pluralName: 'blog-posts';
    singularName: 'blog-post';
  };
  options: {
    draftAndPublish: true;
  };
  attributes: {
    author: Attribute.Relation<
      'api::blog-post.blog-post',
      'manyToOne',
      'plugin::users-permissions.user'
    >;
    categories: Attribute.Relation<
      'api::blog-post.blog-post',
      'manyToMany',
      'api::category.category'
    >;
    content: Attribute.RichText & Attribute.Required;
    createdAt: Attribute.DateTime;
    createdBy: Attribute.Relation<
      'api::blog-post.blog-post',
      'oneToOne',
      'admin::user'
    > &
      Attribute.Private;
    editor_notes: Attribute.Text &
      Attribute.SetMinMaxLength<{
        maxLength: 1000;
      }>;
    excerpt: Attribute.Text &
      Attribute.SetMinMaxLength<{
        maxLength: 500;
      }>;
    featured_image: Attribute.Media<'images'>;
    publishedAt: Attribute.DateTime;
    read_time: Attribute.Integer &
      Attribute.SetMinMax<
        {
          min: 1;
        },
        number
      >;
    seo_description: Attribute.Text &
      Attribute.SetMinMaxLength<{
        maxLength: 160;
      }>;
    seo_title: Attribute.String &
      Attribute.SetMinMaxLength<{
        maxLength: 60;
      }>;
    slug: Attribute.UID<'api::blog-post.blog-post', 'title'> &
      Attribute.Required;
    status: Attribute.Enumeration<
      ['draft', 'in_review', 'approved', 'published', 'rejected']
    > &
      Attribute.Required &
      Attribute.DefaultTo<'draft'>;
    tags: Attribute.Relation<
      'api::blog-post.blog-post',
      'manyToMany',
      'api::tag.tag'
    >;
    title: Attribute.String &
      Attribute.Required &
      Attribute.SetMinMaxLength<{
        maxLength: 255;
      }>;
    updatedAt: Attribute.DateTime;
    updatedBy: Attribute.Relation<
      'api::blog-post.blog-post',
      'oneToOne',
      'admin::user'
    > &
      Attribute.Private;
    views: Attribute.Integer & Attribute.DefaultTo<0>;
  };
}

